import React, { useEffect, useRef, useState } from 'react'
import { useStore } from '../store'
import io from 'socket.io-client'

export default function ChatWindow({ chat }) {
  const currentUser = useStore(s => s.currentUser)
  const token = useStore(s => s.token)
  const focusChat = useStore(s => s.focusChat)
  const closeChat = useStore(s => s.closeChat)
  const messages = useStore(s => s.messages)
  const addMessage = useStore(s => s.addMessage)

  const messagesEndRef = useRef()
  const [text, setText] = useState('')
  const [socket, setSocket] = useState(null)

  useEffect(() => {
    // Connect to Socket.IO
    const newSocket = io('http://localhost:8000/ws', {
      query: { token },
      reconnection: true
    })

    newSocket.on('connect', () => {
      console.log('Connected to chat:', chat.id)
    })

    newSocket.on('message', (msg) => {
      addMessage(msg.receiver_id || msg.sender_id, msg)
    })

    newSocket.on('error', (err) => {
      console.error('Socket error:', err)
    })

    setSocket(newSocket)

    return () => {
      newSocket.off('message')
      newSocket.off('error')
      newSocket.close()
    }
  }, [token, chat.id])

  useEffect(() => {
    // Scroll to bottom
    setTimeout(() => {
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
    }, 100)
  }, [messages[chat.id]])

  const handleSendMessage = () => {
    if (!text.trim() || !socket || !currentUser) return

    socket.emit('send_message', {
      receiver_id: chat.id,
      content: text,
      content_type: 'text'
    }, (res) => {
      if (res?.status === 'ok') {
        addMessage(chat.id, {
          sender_id: currentUser.id,
          receiver_id: chat.id,
          content: text,
          content_type: 'text',
          created_at: new Date().toISOString()
        })
        setText('')
      }
    })
  }

  const chatMessages = messages[chat.id] || []

  return (
    <div
      className="fb-chat-window"
      style={{ zIndex: chat.zIndex }}
      onMouseDown={() => focusChat(chat.id)}
    >
      <div className="fb-chat-header">
        <div className="fb-chat-header-title">{chat.name}</div>
        <button
          className="fb-chat-close"
          onClick={() => closeChat(chat.id)}
          title="Close"
        >
          ×
        </button>
      </div>

      <div className="fb-chat-messages">
        {chatMessages.length === 0 ? (
          <div style={{ padding: '10px', fontSize: '12px', color: '#999' }}>
            No messages yet
          </div>
        ) : (
          chatMessages.map((m, i) => (
            <div
              key={i}
              className={`fb-message ${m.sender_id === currentUser?.id ? 'sent' : 'received'}`}
            >
              {m.content}
            </div>
          ))
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="fb-chat-input">
        <input
          type="text"
          value={text}
          onChange={e => setText(e.target.value)}
          onKeyPress={e => e.key === 'Enter' && handleSendMessage()}
          placeholder="Aa"
        />
        <button onClick={handleSendMessage}>Send</button>
      </div>
    </div>
  )
}
